class User {
  let name: String
  init(name: String) { self.name = name }
  deinit { print("\(name) freed") }
}

do {
  let u1: User? = User(name: "Alice")
  var u2: User? = u1   // refcount 2
  u2 = nil             // refcount 1
} // u1 goes out of scope → refcount 0 → deinit prints

// Cycle — two strong refs hold each other → leak
class A { var b: B? }
class B { var a: A? }
let a = A(); let b = B()
a.b = b; b.a = a
// Both refcount = 1 even after scope exit — leaked.

// Fix: make one side weak
class C { weak var d: D? }
class D { var c: C? }

// Closure capture
class VM {
  var onLoad: (() -> Void)?
  func setup() {
    onLoad = { [weak self] in       // breaks the cycle
      self?.refresh()
    }
  }
  func refresh() {}
}

