// Bug: NSTimer holding target strongly
class Pinger {
  var timer: Timer?
  func start() {
    // ⚠️ Timer retains target — use weak self via block-based init
    timer = Timer.scheduledTimer(withTimeInterval: 1, repeats: true) { [weak self] _ in
      self?.tick()
    }
  }
  deinit { timer?.invalidate() }
  func tick() {}
}

