// Pre-decode image cache
final class ImageCache {
  static let shared = ImageCache()
  private let cache = NSCache<NSURL, UIImage>()
  func image(for url: URL) async -> UIImage? {
    if let img = cache.object(forKey: url as NSURL) { return img }
    let (data, _) = (try? await URLSession.shared.data(from: url)) ?? (Data(), URLResponse())
    let image = await Task.detached { Self.decode(data) }.value
    if let image { cache.setObject(image, forKey: url as NSURL) }
    return image
  }
  private static func decode(_ data: Data) -> UIImage? {
    guard let src = CGImageSourceCreateWithData(data as CFData, nil),
          let cg = CGImageSourceCreateImageAtIndex(src, 0, [
            kCGImageSourceShouldCacheImmediately: true,
            kCGImageSourceCreateThumbnailFromImageAlways: true,
            kCGImageSourceThumbnailMaxPixelSize: 600,
          ] as CFDictionary) else { return nil }
    return UIImage(cgImage: cg)
  }
}

