import os.signpost
let launchLog = OSLog(subsystem: "com.example.app", category: "launch")

@main
struct MyApp: App {
  init() {
    let id = OSSignpostID(log: launchLog)
    os_signpost(.begin, log: launchLog, name: "App.init", signpostID: id)
    // critical only — analytics, db open, theme
    Theme.preload()
    os_signpost(.end, log: launchLog, name: "App.init", signpostID: id)
  }
  var body: some Scene {
    WindowGroup {
      RootView()
        .task {
          // Defer heavy init until after first frame
          await Task.detached { AnalyticsKit.start(); FeatureFlags.refresh() }.value
        }
    }
  }
}

